```typescript
import * as pulumi from "@pulumi/pulumi";
import * as gcp from "@pulumi/gcp";
import * as spacelift from "@spacelift-io/pulumi-spacelift";

const k8s_core = new spacelift.Stack("k8s-core", {
    branch: "master",
    name: "Kubernetes core services",
    repository: "core-infra",
});
const k8s_coreStackGcpServiceAccount = new spacelift.StackGcpServiceAccount("k8s-core", {
    stackId: k8s_core.id,
    tokenScopes: [
        "https://www.googleapis.com/auth/compute",
        "https://www.googleapis.com/auth/cloud-platform",
        "https://www.googleapis.com/auth/devstorage.full_control",
    ],
});
const k8s_coreProject = new gcp.organizations.Project("k8s-core", {
    name: "Kubernetes code",
    projectId: "unicorn-k8s-core",
    orgId: gcpOrganizationId,
});
const k8s_coreIAMMember = new gcp.projects.IAMMember("k8s-core", {
    project: k8s_coreProject.id,
    role: "roles/owner",
    member: pulumi.interpolate`serviceAccount:${k8s_coreStackGcpServiceAccount.serviceAccountEmail}`,
});
