package main

import (
	"fmt"

	"github.com/pulumi/pulumi-gcp/sdk/v9/go/gcp/organizations"
	"github.com/pulumi/pulumi-gcp/sdk/v9/go/gcp/projects"
	"github.com/pulumi/pulumi/sdk/v3/go/pulumi"
	"github.com/spacelift-io/pulumi-spacelift/sdk/v2/go/spacelift"
)

func main() {
	pulumi.Run(func(ctx *pulumi.Context) error {
		k8s_core, err := spacelift.NewStack(ctx, "k8s-core", &spacelift.StackArgs{
			Branch:     pulumi.String("master"),
			Name:       pulumi.String("Kubernetes core services"),
			Repository: pulumi.String("core-infra"),
		})
		if err != nil {
			return err
		}
		k8s_coreStackGcpServiceAccount, err := spacelift.NewStackGcpServiceAccount(ctx, "k8s-core", &spacelift.StackGcpServiceAccountArgs{
			StackId: k8s_core.ID(),
			TokenScopes: pulumi.StringArray{
				pulumi.String("https://www.googleapis.com/auth/compute"),
				pulumi.String("https://www.googleapis.com/auth/cloud-platform"),
				pulumi.String("https://www.googleapis.com/auth/devstorage.full_control"),
			},
		})
		if err != nil {
			return err
		}
		k8s_coreProject, err := organizations.NewProject(ctx, "k8s-core", &organizations.ProjectArgs{
			Name:      pulumi.String("Kubernetes code"),
			ProjectId: pulumi.String("unicorn-k8s-core"),
			OrgId:     pulumi.Any(gcpOrganizationId),
		})
		if err != nil {
			return err
		}
		_, err = projects.NewIAMMember(ctx, "k8s-core", &projects.IAMMemberArgs{
			Project: k8s_coreProject.ID(),
			Role:    pulumi.String("roles/owner"),
			Member: k8s_coreStackGcpServiceAccount.ServiceAccountEmail.ApplyT(func(serviceAccountEmail string) (string, error) {
				return fmt.Sprintf("serviceAccount:%v", serviceAccountEmail), nil
			}).(pulumi.StringOutput),
		})
		if err != nil {
			return err
		}
		return nil
	})
}
